428:     id: ReducerID.uniqueValues,
429:     name: 'All unique values',
430:     description: 'Returns an array with all unique values',
431:     standard: false,
432:     reduce: (field: Field) => ({
433:       uniqueValues: [...new Set(field.values)],
434:     }),
435:     preservesUnits: false,
436:   },
437:   ...buildPercentileReducers(),
438: ]);
