639: /** Calculates standard deviation and variance */
640: function calculateStdDev(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
641:   // Only support number fields
642:   if (!(field.type === FieldType.number || field.type === FieldType.time)) {
643:     return { variance: 0, stdDev: 0 };
644:   }
645: 
646:   let squareSum = 0;
647:   let runningMean = 0;
648:   let runningNonNullCount = 0;
649:   const data = field.values;
650:   for (let i = 0; i < data.length; i++) {
651:     const currentValue = data[i];
652:     if (currentValue != null) {
653:       runningNonNullCount++;
654:       let _oldMean = runningMean;
655:       runningMean += (currentValue - _oldMean) / runningNonNullCount;
656:       squareSum += (currentValue - _oldMean) * (currentValue - runningMean);
657:     }
658:   }
659:   if (runningNonNullCount > 0) {
660:     const variance = squareSum / runningNonNullCount;
661:     return { variance, stdDev: Math.sqrt(variance) };
662:   }
663:   return { variance: 0, stdDev: 0 };
664: }
665: 
666: function calculateChangeCount(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
667:   const data = field.values;
668:   let count = 0;
669:   let first = true;
670:   let last = null;
671:   for (let i = 0; i < data.length; i++) {
672:     let currentValue = data[i];
673:     if (currentValue === null) {
674:       if (ignoreNulls) {
675:         continue;
676:       }
677:       if (nullAsZero) {
678:         currentValue = 0;
679:       }
680:     }
681:     if (!first && last !== currentValue) {
682:       count++;
683:     }
684:     first = false;
685:     last = currentValue;
686:   }
687: 
688:   return { changeCount: count };
689: }
690: 
691: function calculateDistinctCount(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
692:   const data = field.values;
693:   const distinct = new Set();
694:   for (let i = 0; i < data.length; i++) {
695:     let currentValue = data[i];
696:     if (currentValue === null) {
697:       if (ignoreNulls) {
698:         continue;
699:       }
700:       if (nullAsZero) {
701:         currentValue = 0;
702:       }
703:     }
704:     distinct.add(currentValue);
705:   }
706:   return { distinctCount: distinct.size };
707: }
708: 
709: function calculatePercentile(field: Field, percentile: number, ignoreNulls: boolean, nullAsZero: boolean): number {
710:   let data = field.values;
711: 
712:   if (ignoreNulls) {
713:     data = data.filter((value) => value !== null);
714:   }
715:   if (nullAsZero) {
716:     data = data.map((value) => (value === null ? 0 : value));
717:   }
718: 
719:   const sorted = data.slice().sort((a, b) => a - b);
720:   const index = Math.round((sorted.length - 1) * percentile);
721:   return sorted[index];
722: }
723: 
724: function calculateMedian(field: Field<number>, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
725:   const numbers: number[] = [];
726: 
727:   for (let i = 0; i < field.values.length; i++) {
728:     let currentValue = field.values[i];
729: 
730:     if (currentValue == null) {
731:       if (ignoreNulls) {
732:         continue;
733:       }
734:       if (nullAsZero) {
735:         currentValue = 0;
736:       }
737:     }
738: 
739:     numbers.push(currentValue);
740:   }
741: 
742:   numbers.sort((a, b) => a - b);
743: 
744:   const mid = Math.floor(numbers.length / 2);
745: 
746:   if (numbers.length % 2 === 0) {
747:     return { median: (numbers[mid - 1] + numbers[mid]) / 2 };
748:   } else {
749:     return { median: numbers[mid] };
750:   }
751: }
